import grpc
from concurrent import futures
import time
from envoy.service.auth.v3 import external_auth_pb2
from envoy.service.auth.v3 import external_auth_pb2_grpc
from envoy.type.v3 import http_status_pb2
from google.rpc import status_pb2
from google.rpc import code_pb2


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, authorized_tokens=None, required_headers=None):
        self.authorized_tokens = authorized_tokens or set()
        self.required_headers = required_headers or []
        
    def Check(self, request, context):
        try:
            http_request = request.attributes.request.http
            headers = http_request.headers
            
            auth_header = headers.get('authorization', '')
            
            if not auth_header:
                return self._deny_response(
                    code_pb2.UNAUTHENTICATED,
                    "Missing authorization header",
                    401
                )
            
            for required_header in self.required_headers:
                if required_header not in headers:
                    return self._deny_response(
                        code_pb2.PERMISSION_DENIED,
                        f"Missing required header: {required_header}",
                        403
                    )
            
            if auth_header.startswith('Bearer '):
                token = auth_header[7:]
            else:
                token = auth_header
            
            if self.authorized_tokens and token not in self.authorized_tokens:
                return self._deny_response(
                    code_pb2.PERMISSION_DENIED,
                    "Invalid or unauthorized token",
                    403
                )
            
            return self._allow_response(headers)
            
        except Exception as e:
            print(f"Error processing request: {e}")
            return self._deny_response(
                code_pb2.INTERNAL,
                "Internal server error",
                500
            )
    
    def _allow_response(self, request_headers):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-auth-status",
                    value="authorized"
                )
            )
        )
        
        user_id = request_headers.get('x-user-id', 'unknown')
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-validated-user",
                    value=user_id
                )
            )
        )
        
        return response
    
    def _deny_response(self, status_code, message, http_status):
        response = external_auth_pb2.CheckResponse()
        response.status.code = status_code
        response.status.message = message
        
        response.denied_response.status.code = http_status
        
        response.denied_response.headers.add(
            header=external_auth_pb2.HeaderValue(
                key="content-type",
                value="application/json"
            )
        )
        
        response.denied_response.body = f'{{"error": "{message}"}}'
        
        return response


def serve(port=50051, max_workers=10, authorized_tokens=None, required_headers=None):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=max_workers))
    
    auth_service = AuthorizationService(
        authorized_tokens=authorized_tokens,
        required_headers=required_headers
    )
    
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
        auth_service,
        server
    )
    
    server.add_insecure_port(f'[::]:{port}')
    server.start()
    
    print(f"Envoy External Authorization Service running on port {port}")
    print(f"Authorized tokens: {len(authorized_tokens) if authorized_tokens else 0}")
    print(f"Required headers: {required_headers if required_headers else []}")
    
    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        print("\nShutting down server...")
        server.stop(0)


